import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    best_node = None
    min_penalty_time = float('inf')

    for i, customer in enumerate(unvisited_customers):
        arrival_time = current_time + travel_time(cur_truck_pos, customer)
        open_time, close_time = time_windows[i]
        if arrival_time < open_time:
            wait_penalty = open_time - arrival_time
            effective_arrival_time = open_time
        elif open_time <= arrival_time <= close_time:
            wait_penalty = 0
            effective_arrival_time = arrival_time
        else:
            wait_penalty = (arrival_time - close_time) * 10  # Late arrival penalty scaled
            effective_arrival_time = arrival_time

        penalty_time = effective_arrival_time + wait_penalty
        if penalty_time < min_penalty_time:
            min_penalty_time = penalty_time
            best_node = i

    return best_node
